import { useTours } from '../context/TourContext';

const Home = () => {
  const { tours, loading } = useTours();

  return (
    <div className="container mx-auto p-6">
      <header className="text-center mb-10">
        <h1 className="text-4xl font-extrabold text-indigo-900">Discover Your Next Adventure</h1>
        <p className="text-gray-600 mt-2">Browse our exclusive tour packages in Australia</p>
      </header>

      {loading ? (
        <p>Loading tours...</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {tours.map((tour) => (
            <div key={tour._id} className="bg-white rounded-xl shadow-lg overflow-hidden border border-gray-100">
              <div className="p-6">
                <div className="flex justify-between items-center mb-2">
                  <span className="text-sm font-semibold text-indigo-600 uppercase tracking-wider">{tour.duration}</span>
                  <span className="text-xl font-bold text-green-600">${tour.price}</span>
                </div>
                <h3 className="text-xl font-bold mb-2">{tour.title}</h3>
                <p className="text-gray-500 text-sm mb-4">{tour.description}</p>
                <button className="w-full bg-indigo-600 text-white py-2 rounded-lg font-semibold hover:bg-indigo-700 transition">
                  View Details
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Home;
